import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`Successful Completion of Faculty Development Workshop (FDW) – Parts 2 & 3`,date:`26.02.2025`,categories:[`events`],gallery:`FDW-part2-3`,published:!0},{title:i,date:a,categories:o,gallery:s,published:c}=r,l=t(`<p>Over the past weeks, we had the pleasure of hosting Part 2 and Part 3 of our Faculty Development Workshop. These sessions brought together experts in project management and education to exchange knowledge and best practices.</p> <p>FDW Part 2 – February 18, 2025</p> <ul><li>“Set the Scene” Workshop – Led by <strong>John Wall</strong> (South East Technological University), continuing the insightful discussions from previous sessions.</li> <li>Project Management Learning Processes – A deep dive into university-level project management education, presented by <strong>Viktor Morozov, Bohdan Yeremenko, and Oleksander Timinsky</strong> from Taras Shevchenko National University of Kyiv.</li></ul> <p>FDW Part 3 – February 25, 2025</p> <ul><li>The PM² Advantage – A session on the European Commission’s Project Management Methodology, presented by <strong>Nicos Kourounakis</strong> (PM² Alliance).</li> <li>Best Practices in Dissemination & Communication – A practical discussion on visual identity and communication strategies in Erasmus+ KA2 projects, led by <strong>Monika Sońta</strong> (Akademia Leona Kozminskiego).</li></ul> <p>These workshops have been instrumental in enhancing faculty skills, fostering collaboration, and strengthening our academic community! Thank you to all speakers and participants for your engagement and contributions. Looking forward to more enriching sessions ahead!</p>`,1);function u(t){var r=l();e(10),n(t,r)}export{u as default,r as metadata};